import { describe, it, beforeAll, afterAll } from "vitest";
import assert from "node:assert";
import fs from "node:fs";
import os from "node:os";
import path from "node:path";
import { loadOrCreateToken, readToken } from "../../src/server/auth/token.js";
import { withEnv } from "../harness/with-env.js";

describe("auth token directory resolution", () => {
	let dirA: string;
	let dirB: string;

	beforeAll(() => {
		dirA = fs.mkdtempSync(path.join(os.tmpdir(), "bobbit-token-a-"));
		dirB = fs.mkdtempSync(path.join(os.tmpdir(), "bobbit-token-b-"));
	});

	afterAll(() => {
		fs.rmSync(dirA, { recursive: true, force: true });
		fs.rmSync(dirB, { recursive: true, force: true });
	});

	it("uses the current BOBBIT_DIR for each token operation", () => {
		// withEnv snapshots + restores BOBBIT_DIR around each scoped operation.
		const tokenA = withEnv({ BOBBIT_DIR: dirA }, () => {
			const t = loadOrCreateToken();
			assert.strictEqual(readToken(), t);
			assert.strictEqual(fs.readFileSync(path.join(dirA, "state", "token"), "utf-8").trim(), t);
			return t;
		});

		const tokenB = withEnv({ BOBBIT_DIR: dirB }, () => {
			const t = loadOrCreateToken();
			assert.notStrictEqual(t, tokenA);
			assert.strictEqual(readToken(), t);
			assert.strictEqual(fs.readFileSync(path.join(dirB, "state", "token"), "utf-8").trim(), t);
			return t;
		});

		assert.notStrictEqual(tokenB, tokenA);
		assert.strictEqual(fs.readFileSync(path.join(dirA, "state", "token"), "utf-8").trim(), tokenA);
	});
});
